var CONVERSATIONS_AR_ES = [
{ title: "طلب قهوة في مقهى بمدريد", scene: "أنت تدخل مقهى صغيراً قرب محطة مترو في مدريد في الصباح. تريد قهوة بالحليب وخبزاً محمصاً، ثم تسأل عن الدفع بالبطاقة.", lines: [{ who: "them", es: "Buenos días, ¿qué desea?", ar: "صباح الخير، ماذا تريد؟" }, { who: "you", es: "Buenos días, quiero un café con leche, por favor.", ar: "صباح الخير، أريد قهوة بالحليب من فضلك." }, { who: "them", es: "Claro, ¿algo más?", ar: "بالتأكيد، هل تريد شيئاً آخر؟" }, { who: "you", es: "Sí, una tostada sin tomate, gracias.", ar: "نعم، خبزاً محمصاً بدون طماطم، شكراً." }, { who: "them", es: "¿Para tomar aquí o para llevar?", ar: "للتناول هنا أم للسفري؟" }, { who: "you", es: "Para tomar aquí.", ar: "للتناول هنا." }, { who: "them", es: "Muy bien, son cuatro euros.", ar: "جيد جداً، المجموع أربعة يورو." }, { who: "you", es: "¿Acepta tarjeta?", ar: "هل تقبل البطاقة؟" }, { who: "them", es: "Sí, claro.", ar: "نعم، بالتأكيد." }, { who: "you", es: "Gracias, la comida está muy buena.", ar: "شكراً، الطعام جيد جداً." }, { who: "them", es: "Muchas gracias, que tenga buen día.", ar: "شكراً جزيلاً، أتمنى لك يوماً سعيداً." }] },
{ title: "تسجيل الدخول في فندق بإشبيلية", scene: "وصلت إلى فندق في إشبيلية بعد رحلة طويلة. تتحدث مع موظف الاستقبال لتأكيد الحجز وتسأل عن الإفطار والغرفة.", lines: [{ who: "them", es: "Buenas tardes, bienvenido al hotel.", ar: "مساء الخير، أهلاً بك في الفندق." }, { who: "you", es: "Buenas tardes, tengo una reserva.", ar: "مساء الخير، لدي حجز." }, { who: "them", es: "Perfecto, ¿a qué nombre está la reserva?", ar: "ممتاز، باسم من الحجز؟" }, { who: "you", es: "La reserva está a nombre de Ahmed Hassan.", ar: "الحجز باسم أحمد حسن." }, { who: "them", es: "¿Me da su pasaporte, por favor?", ar: "هل تعطيني جواز سفرك من فضلك؟" }, { who: "you", es: "Sí, aquí está mi pasaporte.", ar: "نعم، ها هو جواز سفري." }, { who: "them", es: "Su habitación está en el tercer piso.", ar: "غرفتك في الطابق الثالث." }, { who: "you", es: "Gracias, ¿el desayuno está incluido?", ar: "شكراً، هل الإفطار مشمول؟" }, { who: "them", es: "Sí, de siete a diez de la mañana.", ar: "نعم، من السابعة إلى العاشرة صباحاً." }, { who: "you", es: "Perfecto, ¿dónde está el ascensor?", ar: "ممتاز، أين المصعد؟" }, { who: "them", es: "A la derecha, junto a recepción.", ar: "على اليمين، بجانب الاستقبال." }] },
{ title: "السؤال عن الاتجاهات في فالنسيا", scene: "أنت تمشي في وسط فالنسيا وتبحث عن الساحة الرئيسية. توقف شخصاً محلياً وتسأله بطريقة مهذبة عن الطريق.", lines: [{ who: "you", es: "Disculpa, ¿dónde está la plaza principal?", ar: "عذراً، أين الساحة الرئيسية؟" }, { who: "them", es: "Está cerca, a unos cinco minutos.", ar: "إنها قريبة، حوالي خمس دقائق." }, { who: "you", es: "¿Voy recto?", ar: "هل أذهب بشكل مستقيم؟" }, { who: "them", es: "Sí, siga recto por esta calle.", ar: "نعم، امشِ إلى الأمام في هذا الشارع." }, { who: "you", es: "¿Después giro a la derecha?", ar: "بعد ذلك هل أنعطف يميناً؟" }, { who: "them", es: "No, gire a la izquierda después del puente.", ar: "لا، انعطف يساراً بعد الجسر." }, { who: "you", es: "Entiendo, ¿la plaza está allí?", ar: "فهمت، هل الساحة هناك؟" }, { who: "them", es: "Sí, está frente al museo.", ar: "نعم، إنها أمام المتحف." }, { who: "you", es: "Muchas gracias por su ayuda.", ar: "شكراً جزيلاً على مساعدتك." }, { who: "them", es: "De nada, buen paseo.", ar: "على الرحب والسعة، نزهة سعيدة." }] },
{ title: "شراء تذكرة مترو في برشلونة", scene: "أنت في محطة مترو في برشلونة وتحتاج إلى شراء بطاقة أو تذكرة للوصول إلى وسط المدينة. تتحدث مع موظف بجانب آلة التذاكر.", lines: [{ who: "them", es: "Hola, ¿necesita ayuda?", ar: "مرحباً، هل تحتاج إلى مساعدة؟" }, { who: "you", es: "Sí, quiero un billete para el centro.", ar: "نعم، أريد تذكرة إلى وسط المدينة." }, { who: "them", es: "Puede comprar una tarjeta aquí.", ar: "يمكنك شراء بطاقة هنا." }, { who: "you", es: "¿Cuánto cuesta?", ar: "كم سعرها؟" }, { who: "them", es: "Cuesta once euros con varios viajes.", ar: "سعرها أحد عشر يورو مع عدة رحلات." }, { who: "you", es: "Está bien, pago con tarjeta.", ar: "حسناً، سأدفع بالبطاقة." }, { who: "them", es: "Perfecto, elija esta opción.", ar: "ممتاز، اختر هذا الخيار." }, { who: "you", es: "¿Qué línea va al centro?", ar: "أي خط يذهب إلى وسط المدينة؟" }, { who: "them", es: "La línea tres va al centro.", ar: "الخط الثالث يذهب إلى وسط المدينة." }, { who: "you", es: "Gracias, ¿dónde está el andén?", ar: "شكراً، أين رصيف القطار؟" }, { who: "them", es: "Baje las escaleras y gire a la derecha.", ar: "انزل الدرج وانعطف يميناً." }] },
{ title: "العشاء في مطعم ببوينس آيرس", scene: "أنت في مطعم في بوينس آيرس وتريد طلب العشاء. تسأل النادل عن التوصية، المكونات، والفاتورة في النهاية.", lines: [{ who: "them", es: "Buenas noches, ¿tiene reserva?", ar: "مساء الخير، هل لديك حجز؟" }, { who: "you", es: "No, ¿tiene una mesa para uno?", ar: "لا، هل لديك طاولة لشخص واحد؟" }, { who: "them", es: "Sí, por aquí, por favor.", ar: "نعم، من هنا من فضلك." }, { who: "you", es: "Gracias, ¿qué recomienda?", ar: "شكراً، ماذا تنصح؟" }, { who: "them", es: "Recomiendo el pollo con verduras.", ar: "أنصح بالدجاج مع الخضار." }, { who: "you", es: "Perfecto, quiero ese plato.", ar: "ممتاز، أريد ذلك الطبق." }, { who: "them", es: "¿Y para beber?", ar: "وماذا تريد للشرب؟" }, { who: "you", es: "Agua mineral, por favor.", ar: "مياه معدنية من فضلك." }, { who: "them", es: "Muy bien, enseguida.", ar: "جيد جداً، حالاً." }, { who: "you", es: "Gracias, y después la cuenta, por favor.", ar: "شكراً، وبعد ذلك الفاتورة من فضلك." }, { who: "them", es: "Claro, cuando termine.", ar: "بالتأكيد، عندما تنتهي." }] },
{ title: "التسوق في سوق محلي بمكسيكو سيتي", scene: "أنت تزور سوقاً محلياً في مكسيكو سيتي وتريد شراء فاكهة. تسأل عن السعر والطزاجة وتقرر الدفع نقداً.", lines: [{ who: "them", es: "Buenos días, ¿qué busca?", ar: "صباح الخير، ماذا تبحث عنه؟" }, { who: "you", es: "Busco fruta fresca.", ar: "أبحث عن فاكهة طازجة." }, { who: "them", es: "Tenemos manzanas y naranjas.", ar: "لدينا تفاح وبرتقال." }, { who: "you", es: "¿Cuánto cuesta un kilo de naranjas?", ar: "كم سعر كيلو البرتقال؟" }, { who: "them", es: "Cuesta treinta pesos.", ar: "سعره ثلاثون بيزو." }, { who: "you", es: "Quiero medio kilo, por favor.", ar: "أريد نصف كيلو من فضلك." }, { who: "them", es: "Claro, ¿algo más?", ar: "بالتأكيد، هل شيء آخر؟" }, { who: "you", es: "Sí, dos manzanas también.", ar: "نعم، تفاحتان أيضاً." }, { who: "them", es: "En total son cuarenta pesos.", ar: "المجموع أربعون بيزو." }, { who: "you", es: "Pago en efectivo.", ar: "سأدفع نقداً." }, { who: "them", es: "Gracias, aquí tiene.", ar: "شكراً، تفضل." }] },
{ title: "في الصيدلية بسبب صداع في غرناطة", scene: "تشعر بصداع أثناء التجول في غرناطة وتدخل صيدلية. تريد دواءً بسيطاً وتسأل عن طريقة استخدامه.", lines: [{ who: "them", es: "Hola, ¿en qué puedo ayudarle?", ar: "مرحباً، كيف يمكنني مساعدتك؟" }, { who: "you", es: "Me duele la cabeza.", ar: "رأسي يؤلمني." }, { who: "them", es: "¿Tiene fiebre también?", ar: "هل لديك حمى أيضاً؟" }, { who: "you", es: "No, solo dolor de cabeza.", ar: "لا، فقط صداع." }, { who: "them", es: "Puede tomar estas pastillas.", ar: "يمكنك أخذ هذه الحبوب." }, { who: "you", es: "¿Necesito receta?", ar: "هل أحتاج إلى وصفة طبية؟" }, { who: "them", es: "No, no necesita receta.", ar: "لا، لا تحتاج إلى وصفة." }, { who: "you", es: "¿Cuántas pastillas al día?", ar: "كم حبة في اليوم؟" }, { who: "them", es: "Una cada ocho horas con agua.", ar: "حبة كل ثماني ساعات مع الماء." }, { who: "you", es: "Gracias, ¿cuánto cuesta?", ar: "شكراً، كم السعر؟" }, { who: "them", es: "Cuesta seis euros.", ar: "السعر ستة يورو." }] },
{ title: "حديث ودي مع شخص محلي في سانتياغو", scene: "تجلس في حديقة في سانتياغو ويتحدث معك شخص محلي بطريقة ودية. تتبادلان حديثاً بسيطاً عن السفر والمدينة والموسيقى.", lines: [{ who: "you", es: "Hola, ¿puedo sentarme aquí?", ar: "مرحباً، هل يمكنني الجلوس هنا؟" }, { who: "them", es: "Sí, claro, no hay problema.", ar: "نعم، بالتأكيد، لا توجد مشكلة." }, { who: "you", es: "Gracias, soy turista y estoy de viaje.", ar: "شكراً، أنا سائح وفي رحلة." }, { who: "them", es: "Qué bien, ¿de dónde eres?", ar: "جميل، من أين أنت؟" }, { who: "you", es: "Soy de Marruecos.", ar: "أنا من المغرب." }, { who: "them", es: "Bienvenido, ¿te gusta Santiago?", ar: "أهلاً بك، هل تعجبك سانتياغو؟" }, { who: "you", es: "Sí, me gusta mucho esta ciudad.", ar: "نعم، تعجبني هذه المدينة كثيراً." }, { who: "them", es: "La gente aquí es muy tranquila.", ar: "الناس هنا هادئون جداً." }, { who: "you", es: "Sí, y la comida está deliciosa.", ar: "نعم، والطعام لذيذ." }, { who: "them", es: "¿Qué música te gusta?", ar: "ما الموسيقى التي تحبها؟" }, { who: "you", es: "Me gusta la música latina y árabe.", ar: "أحب الموسيقى اللاتينية والعربية." }, { who: "them", es: "Muy buena combinación.", ar: "مزيج جميل جداً." }] }
];
